const primaryRows = $('Read Primary Sheet').all().map(i => i.json);
const secondaryRows = $('Read Secondary Sheet').all().map(i => i.json);
const now = new Date();
const weekStart = new Date(now - 7 * 24 * 60 * 60 * 1000);
const reportDate = now.toISOString().split('T')[0];
const weekStartDate = weekStart.toISOString().split('T')[0];

// Helper: summarize a sheet's numeric columns
function summarize(rows, label) {
  if (rows.length === 0) return `<p><strong>${label}:</strong> No data</p>`;

  const columns = Object.keys(rows[0]);
  const numericCols = columns.filter(col => {
    const sample = rows.slice(0, 10).map(r => r[col]).filter(v => v !== '' && v != null);
    return sample.length > 0 && sample.every(v => !isNaN(parseFloat(v)));
  });

  let html = `<h3>${label} (${rows.length} rows)</h3>`;
  if (numericCols.length === 0) {
    return html + '<p>No numeric columns found</p>';
  }

  html += '<table border="1" cellpadding="8" cellspacing="0"><tr><th>Metric</th><th>Sum</th><th>Average</th><th>Min</th><th>Max</th></tr>';
  for (const col of numericCols) {
    const vals = rows.map(r => parseFloat(r[col])).filter(v => !isNaN(v));
    if (vals.length === 0) continue;
    const sum = Math.round(vals.reduce((a, b) => a + b, 0) * 100) / 100;
    const avg = Math.round(sum / vals.length * 100) / 100;
    html += `<tr><td><strong>${col}</strong></td><td>${sum}</td><td>${avg}</td><td>${Math.min(...vals)}</td><td>${Math.max(...vals)}</td></tr>`;
  }
  html += '</table>';
  return html;
}

const primarySummary = summarize(primaryRows, 'Primary Data');
const secondarySummary = summarize(secondaryRows, 'Secondary Data');

return [{
  json: {
    report_date: reportDate,
    week_start: weekStartDate,
    primary_rows: primaryRows.length,
    secondary_rows: secondaryRows.length,
    primary_summary: primarySummary,
    secondary_summary: secondarySummary
  }
}];
